# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :author, :string
    belongs_to :user, Blog.Accounts.User

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content, :author])
    |> validate_required([:title, :content])
  end
end

# lib/blog/sanitizer.ex
defmodule Blog.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks.
  Allows safe formatting tags while stripping dangerous elements like
  <script>, <iframe>, event handlers (onclick, onerror, etc.), and
  javascript: URLs.
  """

  # Define a custom scrubber that allows rich formatting but blocks dangerous content
  defmodule BlogScrubber do
    require HtmlSanitizeEx.Scrubber.Meta
    alias HtmlSanitizeEx.Scrubber.Meta

    # Allow basic text formatting
    Meta.strip_comments()

    Meta.allow_tag_with_these_attributes("b", [])
    Meta.allow_tag_with_these_attributes("strong", [])
    Meta.allow_tag_with_these_attributes("i", [])
    Meta.allow_tag_with_these_attributes("em", [])
    Meta.allow_tag_with_these_attributes("u", [])
    Meta.allow_tag_with_these_attributes("s", [])
    Meta.allow_tag_with_these_attributes("strike", [])
    Meta.allow_tag_with_these_attributes("sub", [])
    Meta.allow_tag_with_these_attributes("sup", [])
    Meta.allow_tag_with_these_attributes("br", [])
    Meta.allow_tag_with_these_attributes("hr", [])

    # Block-level elements
    Meta.allow_tag_with_these_attributes("p", ["class"])
    Meta.allow_tag_with_these_attributes("div", ["class"])
    Meta.allow_tag_with_these_attributes("span", ["class"])
    Meta.allow_tag_with_these_attributes("blockquote", ["class"])
    Meta.allow_tag_with_these_attributes("pre", ["class"])
    Meta.allow_tag_with_these_attributes("code", ["class"])

    # Headings
    Meta.allow_tag_with_these_attributes("h1", ["class"])
    Meta.allow_tag_with_these_attributes("h2", ["class"])
    Meta.allow_tag_with_these_attributes("h3", ["class"])
    Meta.allow_tag_with_these_attributes("h4", ["class"])
    Meta.allow_tag_with_these_attributes("h5", ["class"])
    Meta.allow_tag_with_these_attributes("h6", ["class"])

    # Lists
    Meta.allow_tag_with_these_attributes("ul", ["class"])
    Meta.allow_tag_with_these_attributes("ol", ["class"])
    Meta.allow_tag_with_these_attributes("li", ["class"])

    # Tables
    Meta.allow_tag_with_these_attributes("table", ["class"])
    Meta.allow_tag_with_these_attributes("thead", [])
    Meta.allow_tag_with_these_attributes("tbody", [])
    Meta.allow_tag_with_these_attributes("tr", [])
    Meta.allow_tag_with_these_attributes("th", ["class", "colspan", "rowspan"])
    Meta.allow_tag_with_these_attributes("td", ["class", "colspan", "rowspan"])

    # Links - only allow safe href protocols
    Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
    Meta.allow_tag_with_these_attributes("a", ["title", "class", "rel", "target"])

    # Images - only allow safe src protocols
    Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])
    Meta.allow_tag_with_these_attributes("img", ["alt", "title", "class", "width", "height"])

    # Strip everything else (script, iframe, style, form, input, object, embed, etc.)
    Meta.strip_everything_not_covered()
  end

  @doc """
  Sanitizes HTML content, allowing safe rich formatting tags
  while removing all dangerous elements and attributes.
  """
  def sanitize(nil), do: ""
  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, BlogScrubber)
  end
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Sanitizer

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)

    {:ok,
     socket
     |> assign(:page_title, post.title)
     |> assign(:post, post)
     |> assign(:sanitized_content, Sanitizer.sanitize(post.content))}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <article class="blog-post">
        <header class="mb-8">
          <h1 class="text-4xl font-bold text-gray-900 mb-2"><%= @post.title %></h1>
          <div class="text-gray-500 text-sm">
            <span>By <%= @post.author %></span>
            <span class="mx-2">•</span>
            <time datetime={@post.inserted_at}><%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %></time>
          </div>
        </header>

        <div class="prose prose-lg max-w-none">
          <%= Phoenix.HTML.raw(@sanitized_content) %>
        </div>
      </article>

      <div class="mt-8 pt-8 border-t border-gray-200">
        <.link navigate={~p"/posts"} class="text-blue-600 hover:text-blue-800">
          &larr; Back to posts
        </.link>
      </div>
    </div>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Sanitizer

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()

    posts_with_previews =
      Enum.map(posts, fn post ->
        Map.put(post, :preview, generate_preview(post.content))
      end)

    {:ok, assign(socket, :posts, posts_with_previews)}
  end

  defp generate_preview(content) do
    content
    |> Sanitizer.sanitize()
    |> HtmlSanitizeEx.strip_tags()
    |> String.slice(0, 300)
    |> Kernel.<>("...")
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <div class="flex justify-between items-center mb-8">
        <h1 class="text-3xl font-bold">Blog Posts</h1>
        <.link navigate={~p"/posts/new"} class="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700">
          New Post
        </.link>
      </div>

      <div class="space-y-8">
        <article :for={post <- @posts} class="border-b border-gray-200 pb-8">
          <h2 class="text-2xl font-semibold mb-2">
            <.link navigate={~p"/posts/#{post.id}"} class="text-gray-900 hover:text-blue-600">
              <%= post.title %>
            </.link>
          </h2>
          <div class="text-gray-500 text-sm mb-3">
            <span>By <%= post.author %></span>
            <span class="mx-2">•</span>
            <time datetime={post.inserted_at}><%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %></time>
          </div>
          <p class="text-gray-700"><%= post.preview %></p>
        </article>
      </div>
    </div>
    """
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post
  alias Blog.Sanitizer

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})

    {:ok,
     socket
     |> assign(:page_title, "New Post")
     |> assign(:form, to_form(changeset))
     |> assign(:preview_content, nil)
     |> assign(:content, "")}
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, :form, to_form(changeset))}
  end

  @impl true
  def handle_event("preview", %{"post" => %{"content" => content}}, socket) do
    sanitized = Sanitizer.sanitize(content)
    {:noreply, assign(socket, :preview_content, sanitized)}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    # Sanitize content before saving to the database
    sanitized_params = Map.update(post_params, "content", "", &Sanitizer.sanitize/1)

    case Posts.create_post(sanitized_params) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post published successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, :form, to_form(changeset))}
    end
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto px-4 py-8">
      <h1 class="text-3xl font-bold mb-8"><%= @page_title %></h1>

      <.form for={@form} phx-change="validate" phx-submit="save" class="space-y-6">
        <div>
          <label for="post_title" class="block text-sm font-medium text-gray-700 mb-1">Title</label>
          <input
            type="text"
            id="post_title"
            name="post[title]"
            value={@form[:title].value}
            class="w-full border border-gray-300 rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
            required
          />
          <.error :for={msg <- Enum.map(@form[:title].errors, &translate_error/1)}>
            <%= msg %>
          </.error>
        </div>

        <div>
          <label for="post_author" class="block text-sm font-medium text-gray-700 mb-1">Author</label>
          <input
            type="text"
            id="post_author"
            name="post[author]"
            value={@form[:author].value}
            class="w-full border border-gray-300 rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        <div>
          <label for="post_content" class="block text-sm font-medium text-gray-700 mb-1">
            Content (HTML supported)
          </label>
          <div class="text-xs text-gray-500 mb-2">
            Allowed tags: headings, paragraphs, bold, italic, underline, links, images, lists, tables, blockquotes, code blocks.
            Dangerous elements (scripts, iframes, event handlers) are automatically removed.
          </div>
          <textarea
            id="post_content"
            name="post[content]"
            rows="15"
            class="w-full border border-gray-300 rounded px-3 py-2 font-mono text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          ><%= @form[:content].value %></textarea>
          <.error :for={msg <- Enum.map(@form[:content].errors, &translate_error/1)}>
            <%= msg %>
          </.error>
        </div>

        <div class="flex gap-4">
          <button
            type="submit"
            class="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700 font-medium"
          >
            Publish Post
          </button>
          <button
            type="button"
            phx-click="preview"
            phx-value-post={@form[:content].value}
            class="bg-gray-200 text-gray-700 px-6 py-2 rounded hover:bg-gray-300 font-medium"
          >
            Preview
          </button>
          <.link navigate={~p"/posts"} class="text-gray-600 hover:text-gray-800 px-4 py-2">
            Cancel
          </.link>
        </div>
      </.form>

      <div :if={@preview_content} class="mt-8 border-t pt-8">
        <h2 class="text-xl font-semibold mb-4 text-gray-600">Preview</h2>
        <div class="prose prose-lg max-w-none border rounded-lg p-6 bg-white shadow-sm">
          <%= Phoenix.HTML.raw(@preview_content) %>
        </div>
      </div>
    </div>
    """
  end

  defp translate_error({msg, opts}) do
    Enum.reduce(opts, msg, fn {key, value}, acc ->
      String.replace(acc, "%{#{key}}", fn _ -> to_string(value) end)
    end)
  end
end

# lib/blog/posts.ex
defmodule Blog.Posts do
  import Ecto.Query
  alias Blog.Repo
  alias Blog.Posts.Post

  def list_posts do
    Post
    |> order_by(desc: :inserted_at)
    |> Repo.all()
  end

  def get_post!(id), do: Repo.get!(Post, id)

  def create_post(attrs \\ %{}) do
    %Post{}
    |> Post.changeset(attrs)
    |> Repo.insert()
  end

  def update_post(%Post{} = post, attrs) do
    post
    |> Post.changeset(attrs)
    |> Repo.update()
  end

  def delete_post(%Post{} = post) do
    Repo.delete(post)
  end

  def change_post(%Post{} = post, attrs \\ %{}) do
    Post.changeset(post, attrs)
  end
end